#include<bits/stdc++.h>
using namespace std;
long long a[5010],dp[5010][5010],cnt[5010];
int main()
{
    int n,k,q;
    long long ans=0;
    scanf("%d%d%d",&n,&k,&q);
    for(int i=1;i<=n;i++)
    {
        scanf("%lld",&a[i]);
        dp[i][0]=1;
    }
    for(int j=1;j<=k;j++)
    {
        for(int i=1;i<=n;i++)
        {
            dp[i][j]=(dp[i-1][j-1]+dp[i+1][j-1])%(long long)(1e9+7);
        }
    }
    for(int i=1;i<=n;i++)
    {
        for(int j=0;j<=k;j++)
        {
            cnt[i]=(cnt[i]+dp[i][j]*dp[i][k-j])%(long long)(1e9+7);
        }
    }
    for(int i=1;i<=n;i++)
    {
        ans=(ans+cnt[i]*a[i])%(long long)(1e9+7);
    }
    while(q--)
    {
        int x,v;
        scanf("%d%d",&x,&v);
        ans=(ans-a[x]*cnt[x])%(long long)(1e9+7);
        a[x]=v;
        ans=(ans+a[x]*cnt[x])%(long long)(1e9+7);
        printf("%lld\n",(ans+(long long)(1e9+7))%(long long)(1e9+7));
    }
    return 0;
}
